func mergeReviewDisplayName(soldier models.Soldier) string {
	name := strings.TrimSpace(strings.TrimSpace(soldier.FirstName + " " + soldier.MiddleName + " " + soldier.LastName))
	if name == "" {
		return soldier.DisplayID
	}
	return name
}

